query.text:
if dbo.FastBusiness$Function$CheckSQLInjection(@stt_rec) = 0 return declare @m_ma_nt0 varchar(10) select @m_ma_nt0 = val from options where name = 'm_ma_nt0' select rtrim(a.ong_ba) as ong_ba, rtrim(b.ma_kh) as ma_kh, b.ten_kh, b.ten_kh2, dien_giai, ltrim(a.so_ct) so_ct, a.t_so_luong, a.t_tien, a.t_tien_nt, a.t_nk, a.t_nk_nt,a.t_ttdb, a.t_ttdb_nt,a.t_cp, a.t_cp_nt,a.t_thue, a.t_thue_nt, a.t_tt, a.t_tt_nt, a.ngay_ct0, dbo.FastBusiness$Function$System$ReadCurrency(@m_ma_nt0, a.t_tt, @@language) as t_tt_in_word, dbo.FastBusiness$Function$System$ReadCurrency(a.ma_nt, a.t_tt_nt, @@language) as t_tt_nt_in_word, replace(str(day(a.ngay_ct),2),' ','0') ngay, replace(str(month(a.ngay_ct),2),' ','0') thang, cast(year(a.ngay_ct) as char(4)) nam, replace(str(day(a.ngay_ct0),2),' ','0') ngay0, replace(str(month(a.ngay_ct0),2),' ','0') thang0, cast(year(a.ngay_ct0) as char(4)) nam0 , &Master.XMLSelect; as customize from @@prime$partition$current a with(nolock) left join dmkh b with(nolock) on a.ma_kh = b.ma_kh left join d98$$partition$current c with(nolock) on (a.stt_rec = c.stt_rec and c.stt_rec0 = (select min(stt_rec0) from d98$$partition$current with(nolock) where stt_rec = a.stt_rec)) left join dmkho d with(nolock) on c.ma_kho = d.ma_kho &Master.Join; where a.stt_rec = @stt_rec
declare @key varchar(128) select @key = 'a.stt_rec = ''' + @stt_rec + '''' exec rs_PrintPKTran @@language, @key, 'd98$$partition$current', @@id&externalDetail;
&Conditional.Unit.Profile.Query.Declare; &Conditional.Unit.Profile.Query.Select; &Conditional.Unit.Profile.Query.Result;
